"use strict";(globalThis.webpackChunklitesaml_docs=globalThis.webpackChunklitesaml_docs||[]).push([[291],{4292(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/cookbook/docs/intro","label":"Introduction","docId":"intro","unlisted":false},{"type":"category","label":"Getting Started","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/cookbook/docs/getting-started/","label":"Overview","docId":"getting-started/index","unlisted":false},{"type":"link","href":"/cookbook/docs/getting-started/service-provider","label":"Service Provider","docId":"getting-started/service-provider","unlisted":false},{"type":"link","href":"/cookbook/docs/getting-started/identity-provider","label":"Identity Provider","docId":"getting-started/identity-provider","unlisted":false},{"type":"link","href":"/cookbook/docs/getting-started/upgrade","label":"Upgrade from lightsaml","docId":"getting-started/upgrade","unlisted":false}],"href":"/cookbook/docs/category/getting-started"},{"type":"category","label":"Metadata","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/cookbook/docs/metadata/","label":"Overview","docId":"metadata/index","unlisted":false},{"type":"link","href":"/cookbook/docs/metadata/generate","label":"Generate metadata","docId":"metadata/generate","unlisted":false},{"type":"link","href":"/cookbook/docs/metadata/parse","label":"Parse metadata","docId":"metadata/parse","unlisted":false}],"href":"/cookbook/docs/category/metadata"},{"type":"category","label":"Authentication","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/cookbook/docs/authentication/","label":"Overview","docId":"authentication/index","unlisted":false},{"type":"link","href":"/cookbook/docs/authentication/authn-request","label":"Authentication request","docId":"authentication/authn-request","unlisted":false},{"type":"link","href":"/cookbook/docs/authentication/authn-response","label":"Authentication response","docId":"authentication/authn-response","unlisted":false}],"href":"/cookbook/docs/category/authentication"},{"type":"category","label":"Single Logout","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/cookbook/docs/single-logout/","label":"Overview","docId":"single-logout/index","unlisted":false},{"type":"link","href":"/cookbook/docs/single-logout/logout-request","label":"Logout request","docId":"single-logout/logout-request","unlisted":false},{"type":"link","href":"/cookbook/docs/single-logout/logout-response","label":"Logout response","docId":"single-logout/logout-response","unlisted":false}],"href":"/cookbook/docs/category/single-logout"},{"type":"category","label":"Security","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/cookbook/docs/security/generate-key-pair","label":"Generate a key pair","docId":"security/generate-key-pair","unlisted":false},{"type":"link","href":"/cookbook/docs/security/","label":"Security","docId":"security/index","unlisted":false},{"type":"link","href":"/cookbook/docs/security/sign-message","label":"Sign message","docId":"security/sign-message","unlisted":false},{"type":"link","href":"/cookbook/docs/security/verify-signature","label":"Verify signature","docId":"security/verify-signature","unlisted":false},{"type":"link","href":"/cookbook/docs/security/encrypt-assertion","label":"Encrypt assertion","docId":"security/encrypt-assertion","unlisted":false},{"type":"link","href":"/cookbook/docs/security/decrypt-assertion","label":"Decrypt assertion","docId":"security/decrypt-assertion","unlisted":false}],"href":"/cookbook/docs/category/security"},{"type":"link","href":"/cookbook/docs/contributing","label":"Contributing","docId":"contributing","unlisted":false}]},"docs":{"authentication/authn-request":{"id":"authentication/authn-request","title":"Authentication request","description":"An AuthnRequest is sent by the SP to the IdP to initiate the authentication flow. The IdP receives and processes it, then authenticates the user.","sidebar":"tutorialSidebar"},"authentication/authn-response":{"id":"authentication/authn-response","title":"Authentication response","description":"After authenticating the user, the IdP sends an AuthnResponse to the SP\'s ACS endpoint. The SP then reads the response to retrieve the user\'s identity and attributes.","sidebar":"tutorialSidebar"},"authentication/index":{"id":"authentication/index","title":"Overview","description":"The SAML authentication flow involves two steps:","sidebar":"tutorialSidebar"},"contributing":{"id":"contributing","title":"Contributing","description":"Welcome and thanks for contributing to this project.","sidebar":"tutorialSidebar"},"getting-started/identity-provider":{"id":"getting-started/identity-provider","title":"Identity Provider","description":"An Identity Provider (IdP) authenticates users on behalf of Service Providers. This page shows how to configure an IdentityProviderWrapper and use it to respond to authentication requests.","sidebar":"tutorialSidebar"},"getting-started/index":{"id":"getting-started/index","title":"Overview","description":"litesaml/saml exposes two wrapper classes that map to the two SAML 2.0 roles:","sidebar":"tutorialSidebar"},"getting-started/service-provider":{"id":"getting-started/service-provider","title":"Service Provider","description":"A Service Provider (SP) delegates user authentication to an Identity Provider (IdP). This page shows how to configure a ServiceProviderWrapper and use it to authenticate users.","sidebar":"tutorialSidebar"},"getting-started/upgrade":{"id":"getting-started/upgrade","title":"Upgrade from lightsaml","description":"litesaml/saml is a high-level rewrite of litesaml/lightsaml. The API is not backwards-compatible \u2014 this guide covers every breaking change and shows before/after examples for the most common patterns.","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"Introduction","description":"litesaml/saml is a PHP library for implementing the SAML 2.0 protocol. It provides high-level wrappers for both Service Provider (SP) and Identity Provider (IdP) roles, handling authentication requests, responses, single logout, metadata, and message security.","sidebar":"tutorialSidebar"},"metadata/generate":{"id":"metadata/generate","title":"Generate metadata","description":"Both ServiceProviderWrapper and IdentityProviderWrapper can generate an XML metadata document for their respective entity. Share this metadata with the other party so they can configure the trust relationship.","sidebar":"tutorialSidebar"},"metadata/index":{"id":"metadata/index","title":"Overview","description":"SAML metadata is an XML document that describes a SAML entity (SP or IdP). It declares the entity\'s identifier, its endpoints (SSO, SLO, ACS), and the certificates used for signing and encryption.","sidebar":"tutorialSidebar"},"metadata/parse":{"id":"metadata/parse","title":"Parse metadata","description":"MetadataParser::parse() parses any SAML metadata XML and returns an Entity (either Idp or Sp) or an EntityList when the document is a federation EntitiesDescriptor.","sidebar":"tutorialSidebar"},"security/decrypt-assertion":{"id":"security/decrypt-assertion","title":"Decrypt assertion","description":"When the IdP sends encrypted assertions, the SP decrypts them automatically in handleAuthnResponse() \u2014 provided the Sp descriptor is configured with an encryption Certificate that includes a PrivateKey.","sidebar":"tutorialSidebar"},"security/encrypt-assertion":{"id":"security/encrypt-assertion","title":"Encrypt assertion","description":"The IdP can encrypt individual attributes so that only the intended SP can decrypt them. This is done at the attribute level true when calling sendAuthnResponse().","sidebar":"tutorialSidebar"},"security/generate-key-pair":{"id":"security/generate-key-pair","title":"Generate a key pair","description":"SAML security features (signing and encryption) require a key pair: a certificate (public key) and a private key. The certificate is shared with your SAML partners and published in your metadata. The private key must remain secret.","sidebar":"tutorialSidebar"},"security/index":{"id":"security/index","title":"Security","description":"litesaml/saml supports message signing, signature verification, assertion encryption, and assertion decryption. All security features are configured through descriptor classes (Sp, Idp) and are applied automatically by the wrappers.","sidebar":"tutorialSidebar"},"security/sign-message":{"id":"security/sign-message","title":"Sign message","description":"Message signing is automatic in litesaml/saml. When a Certificate with a PrivateKey is configured as the signing property on your Sp or Idp descriptor, all outgoing messages are signed without any extra code.","sidebar":"tutorialSidebar"},"security/verify-signature":{"id":"security/verify-signature","title":"Verify signature","description":"Signatures can be verified either automatically at the point of receiving a message, or manually after the fact.","sidebar":"tutorialSidebar"},"single-logout/index":{"id":"single-logout/index","title":"Overview","description":"Single Logout (SLO) allows either the SP or the IdP to terminate all active sessions across the federation. The flow consists of a logout request followed by a logout response.","sidebar":"tutorialSidebar"},"single-logout/logout-request":{"id":"single-logout/logout-request","title":"Logout request","description":"A LogoutRequest is sent by either the SP or the IdP to initiate single logout. The recipient terminates the user\'s session and replies with a LogoutResponse.","sidebar":"tutorialSidebar"},"single-logout/logout-response":{"id":"single-logout/logout-response","title":"Logout response","description":"A LogoutResponse is sent in reply to a LogoutRequest. It confirms that the session has been terminated.","sidebar":"tutorialSidebar"}}}}')}}]);